const raw =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.content ||
  "";

let texto = String(raw).trim();

// =====================================
// REMOVE BLOCO MARKDOWN
// =====================================
texto = texto
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

// =====================================
// REMOVE QUEBRAS E ESCAPES EXTRAS
// =====================================
texto = texto
  .replace(/\r/g, "")
  .replace(/\n/g, " ")
  .replace(/\t/g, " ")
  .trim();

// =====================================
// LOCALIZA ARRAY JSON
// =====================================
const inicio = texto.indexOf("[");
const fim = texto.lastIndexOf("]");

if (inicio === -1 || fim === -1) {
  throw new Error(
    "A IA não retornou um ARRAY JSON válido."
  );
}

let jsonTexto = texto.slice(inicio, fim + 1);

// =====================================
// REMOVE ESCAPES DUPLOS
// =====================================
if (jsonTexto.includes('\\"')) {
  jsonTexto = jsonTexto
    .replace(/\\"/g, '"')
    .replace(/\\\\/g, "\\");
}

// =====================================
// REMOVE ASPAS EXTERNAS
// =====================================
if (
  jsonTexto.startsWith('"[') &&
  jsonTexto.endsWith(']"')
) {
  jsonTexto = jsonTexto
    .slice(1, -1);
}

// =====================================
// CONVERTE JSON
// =====================================
let dados;

try {
  dados = JSON.parse(jsonTexto);
} catch (e) {

  // =====================================
  // TENTA NOVAMENTE COM JSON.parse DUPLO
  // =====================================
  try {
    dados = JSON.parse(
      JSON.parse(JSON.stringify(jsonTexto))
    );
  } catch (e2) {
    throw new Error(
      "Erro ao converter JSON da IA: " +
      e.message
    );
  }
}

// =====================================
// GARANTE ARRAY
// =====================================
if (!Array.isArray(dados)) {
  dados = [dados];
}

// =====================================
// NORMALIZA CAMPOS
// =====================================
const resultado = dados.map((item, index) => {

  const exames =
    Array.isArray(item.EXAMES)
      ? item.EXAMES
      : String(item.EXAMES || "")
          .split(",")
          .map(e => e.trim())
          .filter(Boolean);

  return {
    json: {
      sucesso: true,

      categoria:
        item.categoria ||
        "(+)COMPUTADOR DO POSTO",

      PACIENTE:
        String(item.PACIENTE || "").trim(),

      EXAMES: exames,

      EXAMES_TEXTO:
        exames.join(", "),

      QTD_EXAMES:
        exames.length,

      VALOR:
        Number(item.VALOR || 0),

      posto:
        String(
          item.posto || ""
        ).trim(),

      data:
        String(
          item.data || ""
        ).trim(),

      _idx: index + 1,

      _totalPacientes:
        dados.length
    }
  };
});

// =====================================
// REMOVE DUPLICADOS
// =====================================
const vistos = new Set();

const unicos = [];

for (const item of resultado) {

  const chave =
    `${item.json.PACIENTE}|${item.json.EXAMES_TEXTO}|${item.json.data}`;

  if (!vistos.has(chave)) {
    vistos.add(chave);
    unicos.push(item);
  }
}

return unicos;

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function palavrasDoNome(nome) {
  return normalizarTexto(nome)
    .split(" ")
    .filter(Boolean);
}

function contarPalavrasIguais(nome1, nome2) {
  const palavras1 = new Set(palavrasDoNome(nome1));
  const palavras2 = new Set(palavrasDoNome(nome2));

  let iguais = 0;

  for (const palavra of palavras1) {
    if (palavras2.has(palavra)) {
      iguais++;
    }
  }

  return iguais;
}

// ======================================================
// REGRA:
// Só dá match se as 3 primeiras palavras forem iguais
// e estiverem na mesma sequência.
// ======================================================
function tresPrimeirasPalavrasIguaisNaSequencia(nome1, nome2) {
  const palavras1 = palavrasDoNome(nome1);
  const palavras2 = palavrasDoNome(nome2);

  if (palavras1.length < 3 || palavras2.length < 3) {
    return false;
  }

  const tresPrimeiras1 = palavras1.slice(0, 3).join(" ");
  const tresPrimeiras2 = palavras2.slice(0, 3).join(" ");

  return tresPrimeiras1 === tresPrimeiras2;
}

function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) {
    return valor;
  }

  if (typeof valor === "string") {
    return valor
      .split(/,|;|\n/)
      .map(v => v.trim())
      .filter(Boolean);
  }

  return [valor];
}

function compararExames(exames1, exames2) {
  const examesInput1 = garantirArray(exames1);
  const examesInput2 = garantirArray(exames2);

  const examesInput1Norm = examesInput1.map(normalizarTexto);
  const examesInput2Norm = examesInput2.map(normalizarTexto);

  const examesFaltando = examesInput1.filter(exame =>
    !examesInput2Norm.includes(normalizarTexto(exame))
  );

  const examesExtras = examesInput2.filter(exame =>
    !examesInput1Norm.includes(normalizarTexto(exame))
  );

  const matchExames =
    examesFaltando.length === 0 &&
    examesExtras.length === 0 &&
    examesInput1.length === examesInput2.length;

  return {
    examesInput1,
    examesInput2,
    examesFaltando,
    examesExtras,
    matchExames
  };
}

// ================================
// LÊ TODOS OS ITENS DO MERGE
// ================================
const todos = $input.all().map(i => i.json);

// ================================
// SEPARA INPUTS POR CATEGORIA
// input1 = computador do posto
// input2 = relatório de motoqueiros
// ================================
let input1 = todos.filter(i =>
  i.PACIENTE &&
  Array.isArray(i.EXAMES) &&
  normalizarTexto(i.categoria).includes("COMPUTADOR DO POSTO")
);

let input2 = todos.filter(i =>
  i.PACIENTE &&
  Array.isArray(i.EXAMES) &&
  normalizarTexto(i.categoria).includes("RELATORIO DE MOTOQUEIROS")
);

// ======================================================
// FALLBACK DE SEGURANÇA
// Só usa metade/metade se não conseguir separar por categoria
// ======================================================
if (input1.length === 0 || input2.length === 0) {
  const metade = Math.ceil(todos.length / 2);

  input1 = todos.slice(0, metade).filter(i =>
    i.PACIENTE &&
    Array.isArray(i.EXAMES)
  );

  input2 = todos.slice(metade).filter(i =>
    i.PACIENTE &&
    Array.isArray(i.EXAMES)
  );
}

// ================================
// DADOS GERAIS
// ================================
const posto =
  input1[0]?.posto ||
  input2[0]?.posto ||
  "";

const data =
  input1[0]?.data ||
  input2[0]?.data ||
  "";

const resultado = [];

// Guarda os índices do input2 que já foram usados
const indicesInput2Usados = new Set();

// ================================
// COMPARAÇÃO DO INPUT1 CONTRA INPUT2
// ================================
for (const item1 of input1) {
  const pacienteInput1 = item1.PACIENTE || "";
  const examesInput1 = garantirArray(item1.EXAMES);

  let melhorMatch = null;
  let melhorIndiceInput2 = -1;
  let maiorQtdPalavrasIguais = 0;
  let melhorComparacaoExames = null;

  // ======================================================
  // 1) PRIMEIRA TENTATIVA:
  // procura paciente compatível + exames iguais + input2 não usado
  // ======================================================
  for (let idx = 0; idx < input2.length; idx++) {
    if (indicesInput2Usados.has(idx)) continue;

    const item2 = input2[idx];
    const pacienteInput2 = item2.PACIENTE || "";

    const nome1Normalizado = normalizarTexto(pacienteInput1);
    const nome2Normalizado = normalizarTexto(pacienteInput2);

    const nomeCompletoIgual =
      nome1Normalizado === nome2Normalizado;

    const match3Palavras =
      tresPrimeirasPalavrasIguaisNaSequencia(
        pacienteInput1,
        pacienteInput2
      );

    const matchPaciente = Boolean(
      nomeCompletoIgual || match3Palavras
    );

    if (!matchPaciente) continue;

    const comparacaoExames = compararExames(
      examesInput1,
      item2.EXAMES
    );

    if (comparacaoExames.matchExames) {
      melhorMatch = item2;
      melhorIndiceInput2 = idx;
      maiorQtdPalavrasIguais = contarPalavrasIguais(
        pacienteInput1,
        pacienteInput2
      );
      melhorComparacaoExames = comparacaoExames;
      break;
    }
  }

  // ======================================================
  // 2) SEGUNDA TENTATIVA:
  // se não achou exames iguais, procura paciente compatível
  // para retornar divergência de exames.
  // ======================================================
  if (!melhorMatch) {
    for (let idx = 0; idx < input2.length; idx++) {
      if (indicesInput2Usados.has(idx)) continue;

      const item2 = input2[idx];
      const pacienteInput2 = item2.PACIENTE || "";

      const nome1Normalizado = normalizarTexto(pacienteInput1);
      const nome2Normalizado = normalizarTexto(pacienteInput2);

      const nomeCompletoIgual =
        nome1Normalizado === nome2Normalizado;

      const match3Palavras =
        tresPrimeirasPalavrasIguaisNaSequencia(
          pacienteInput1,
          pacienteInput2
        );

      const matchPaciente = Boolean(
        nomeCompletoIgual || match3Palavras
      );

      if (!matchPaciente) continue;

      const qtdPalavrasIguais = contarPalavrasIguais(
        pacienteInput1,
        pacienteInput2
      );

      if (qtdPalavrasIguais > maiorQtdPalavrasIguais) {
        maiorQtdPalavrasIguais = qtdPalavrasIguais;
        melhorMatch = item2;
        melhorIndiceInput2 = idx;
        melhorComparacaoExames = compararExames(
          examesInput1,
          item2.EXAMES
        );
      }
    }
  }

  // ================================
  // VALIDAÇÃO FINAL DO NOME
  // ================================
  const nome1Normalizado = normalizarTexto(pacienteInput1);

  const nome2Normalizado = melhorMatch
    ? normalizarTexto(melhorMatch.PACIENTE || "")
    : "";

  const nomeCompletoIgual =
    nome1Normalizado === nome2Normalizado;

  const match3Palavras =
    melhorMatch
      ? tresPrimeirasPalavrasIguaisNaSequencia(
          pacienteInput1,
          melhorMatch.PACIENTE || ""
        )
      : false;

  const matchPaciente = Boolean(
    melhorMatch &&
    (
      nomeCompletoIgual ||
      match3Palavras
    )
  );

  const pacienteInput2Encontrado =
    matchPaciente
      ? melhorMatch.PACIENTE || ""
      : "";

  const examesInput2 =
    matchPaciente
      ? garantirArray(melhorMatch.EXAMES)
      : [];

  if (!melhorComparacaoExames) {
    melhorComparacaoExames = compararExames(
      examesInput1,
      examesInput2
    );
  }

  const examesFaltando = matchPaciente
    ? melhorComparacaoExames.examesFaltando
    : examesInput1;

  const examesExtras = matchPaciente
    ? melhorComparacaoExames.examesExtras
    : [];

  const matchExames =
    matchPaciente &&
    melhorComparacaoExames.matchExames;

  // Marca esse input2 como usado somente se encontrou paciente
  if (matchPaciente && melhorIndiceInput2 >= 0) {
    indicesInput2Usados.add(melhorIndiceInput2);
  }

  resultado.push({
    json: {
      origemResultado: "INPUT1_COMPARADO_COM_INPUT2",

      posto,
      data,

      PACIENTE_INPUT1: pacienteInput1,
      PACIENTE_INPUT2: pacienteInput2Encontrado,

      matchPaciente,

      nomeCompletoIgual,

      matchPor3Palavras:
        !nomeCompletoIgual &&
        match3Palavras,

      palavrasIguaisPaciente:
        maiorQtdPalavrasIguais,

      primeiras3PalavrasInput1:
        palavrasDoNome(pacienteInput1).slice(0, 3),

      primeiras3PalavrasInput2:
        pacienteInput2Encontrado
          ? palavrasDoNome(pacienteInput2Encontrado).slice(0, 3)
          : [],

      matchExames,

      quantidadeExamesInput1:
        examesInput1.length,

      quantidadeExamesInput2:
        examesInput2.length,

      examesInput1,
      examesInput2,

      examesFaltandoNoInput2:
        examesFaltando,

      examesExtrasNoInput2:
        examesExtras,

      erro: !matchExames,

      mensagem:
        matchExames
          ? "Paciente e exames estão exatamente iguais"
          : matchPaciente
            ? "Paciente encontrado pelas 3 primeiras palavras na sequência, mas há divergência entre os exames"
            : "Paciente não encontrado no input2 com nome completo igual nem com as 3 primeiras palavras iguais na sequência"
    }
  });
}

// ======================================================
// NOVA PARTE:
// RETORNA TAMBÉM OS PACIENTES DO INPUT2 QUE NÃO DERAM MATCH
// ======================================================
for (let idx = 0; idx < input2.length; idx++) {
  if (indicesInput2Usados.has(idx)) continue;

  const item2 = input2[idx];

  const pacienteInput2 = item2.PACIENTE || "";
  const examesInput2 = garantirArray(item2.EXAMES);

  resultado.push({
    json: {
      origemResultado: "INPUT2_SEM_MATCH_NO_INPUT1",

      posto: item2.posto || posto,
      data: item2.data || data,

      PACIENTE_INPUT1: "",
      PACIENTE_INPUT2: pacienteInput2,

      matchPaciente: false,

      nomeCompletoIgual: false,

      matchPor3Palavras: false,

      palavrasIguaisPaciente: 0,

      primeiras3PalavrasInput1: [],

      primeiras3PalavrasInput2:
        palavrasDoNome(pacienteInput2).slice(0, 3),

      matchExames: false,

      quantidadeExamesInput1: 0,

      quantidadeExamesInput2:
        examesInput2.length,

      examesInput1: [],

      examesInput2,

      examesFaltandoNoInput2: [],

      examesExtrasNoInput2:
        examesInput2,

      erro: true,

      mensagem:
        "Paciente existe no input2, mas não foi encontrado correspondente no input1"
    }
  });
}

return resultado;

